def validate_chat_request(raw: dict) -> ChatRequest | None:
    try:
        return ChatRequest.model_validate(raw)
    except ValidationError as e:
        logger.warning("Input validation failed", extra={
            "errors": e.errors(),
            "user_id": raw.get("user_id", "unknown"),
        })
        return None

