from fastapi import FastAPI, Request, HTTPException
from fastapi.responses import JSONResponse
import time, logging, json

from input_validator import validate_chat_request

app = FastAPI()
logger = logging.getLogger(__name__)

@app.middleware("http")
async def input_validation_middleware(request: Request, call_next):
    if request.url.path == "/v1/chat" and request.method == "POST":
        start = time.monotonic()
        try:
            body = await request.body()
            raw = json.loads(body)
        except Exception:
            return JSONResponse(
                status_code=400,
                content={"error": "invalid_json", "message": "Request body must be valid JSON"},
            )

        validated = validate_chat_request(raw)
        if validated is None:
            return JSONResponse(
                status_code=422,
                content={
                    "error": "validation_failed",
                    "message": "Input did not pass validation checks. "
                               "Ensure messages are within length limits and contain no PII.",
                },
            )

        # Attach validated model to request state for the handler
        request.state.validated_request = validated
        latency_ms = (time.monotonic() - start) * 1000
        logger.info("Input validated", extra={"latency_ms": latency_ms})

    return await call_next(request)


@app.post("/v1/chat")
async def chat(request: Request):
    validated = request.state.validated_request
    # Proceed to inference with clean, validated input
    return {"status": "ok", "message_count": len(validated.messages)}

